module sync_up_counter_4bit(
    input               clk     ,   
    input               rst     ,
    input               en      ,
    output  reg [3:0]   count    
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk) begin
    if (rst)
        count <= 4'd0;
    else if (en)
        count <= count + 1;
end

endmodule
